import React, { useState } from 'react';
import axios from 'axios';
import './App.css';

function App() {
  const [code, setCode] = useState('');
  const [prompt, setPrompt] = useState('');
  const [output, setOutput] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(false);

  const handleSubmit = async () => {
    console.log('\n========== FRONTEND REQUEST START ==========');
    console.log('📝 Code:', code.substring(0, 100) + '...');
    console.log('💬 Prompt:', prompt);

    if (!code.trim() || !prompt.trim()) {
      console.log('❌ Validation failed: Missing code or prompt');
      setOutput('Please enter both code and prompt!');
      setError(true);
      return;
    }

    setLoading(true);
    setError(false);
    setOutput('AI is thinking...');

    const requestPayload = {
      code,
      prompt
    };

    console.log('📤 Sending to Backend:', JSON.stringify(requestPayload, null, 2));

    try {
      const response = await axios.post('http://localhost:3000/api/improve-code', requestPayload);

      console.log('✅ Response Received from Backend');
      console.log('📥 Response Data:', response.data);
      console.log('📊 Chat History Length:', response.data.chatHistoryLength);
      console.log('📝 Improved Code Length:', response.data.improvedCode.length);

      setCode(response.data.improvedCode);
      setOutput(response.data.improvedCode);
      setError(false);
      
      console.log('✅ UI Updated Successfully');
    } catch (err) {
      console.error('❌ ERROR:', err);
      console.error('❌ Error Response:', err.response?.data);
      console.error('❌ Error Message:', err.message);
      
      setOutput(`Error: ${err.response?.data?.error || err.message}`);
      setError(true);
    } finally {
      setLoading(false);
      console.log('========== FRONTEND REQUEST COMPLETE ==========\n');
    }
  };

  return (
    <div className="container">
      <h1>AI Code Editor</h1>
      
      <div className="editor-section">
        <h3>Code Editor</h3>
        <textarea
          id="codeEditor"
          value={code}
          onChange={(e) => setCode(e.target.value)}
          placeholder="Write your code here..."
        />
      </div>

      <div className="prompt-section">
        <input
          type="text"
          value={prompt}
          onChange={(e) => setPrompt(e.target.value)}
          placeholder="Tell AI what changes you want (e.g., 'add error handling')"
          onKeyPress={(e) => e.key === 'Enter' && handleSubmit()}
        />
        <button onClick={handleSubmit} disabled={loading}>
          {loading ? 'Processing...' : 'Ask AI'}
        </button>
      </div>

      <div className="output-section">
        <h3>AI Response</h3>
        <div className={`output ${error ? 'error' : ''} ${loading ? 'loading' : ''}`}>
          {output || 'AI response will appear here...'}
        </div>
      </div>
    </div>
  );
}

export default App;
